from flask import Flask, request, session, redirect, url_for, render_template_string, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
from itsdangerous import TimedJSONWebSignatureSerializer as Serializer
import pyotp
import qrcode
import io
import base64
import os
import secrets
from datetime import datetime, timedelta

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(16))

# Mock user database
users_db = {}
mfa_tokens = {}

# Secure session management
def generate_secure_token():
    return secrets.token_urlsafe(32)

def create_serializer():
    return Serializer(app.secret_key, expires_in=3600)

def verify_token(token):
    serializer = create_serializer()
    try:
        data = serializer.loads(token)
        return data
    except:
        return None

def store_mfa_token(user_id, token):
    mfa_tokens[user_id] = {
        'token': token,
        'created_at': datetime.utcnow()
    }

def is_token_valid(user_id, token):
    if user_id not in mfa_tokens:
        return False
    stored_token = mfa_tokens[user_id]
    if (datetime.utcnow() - stored_token['created_at']) > timedelta(minutes=10):
        del mfa_tokens[user_id]
        return False
    return stored_token['token'] == token

@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        if not username or not password:
            return "Username and password required", 400
        
        if username in users_db:
            return "User already exists", 400
            
        users_db[username] = {
            'password_hash': generate_password_hash(password),
            'totp_secret': pyotp.random_base32()
        }
        
        # Generate QR code for MFA setup
        totp_uri = pyotp.totp.TOTP(users_db[username]['totp_secret']).provisioning_uri(
            username, issuer_name="SecureApp"
        )
        
        qr = qrcode.QRCode(version=1, box_size=10, border=4)
        qr.add_data(totp_uri)
        qr.make(fit=True)
        
        img = qr.make_image(fill_color="black", back_color="white")
        img_buffer = io.BytesIO()
        img.save(img_buffer)
        img_buffer.seek(0)
        img_base64 = base64.b64encode(img_buffer.getvalue()).decode()
        
        return render_template_string('''
            <h2>Registration Successful</h2>
            <p>Scan this QR code with your authenticator app:</p>
            <img src="data:image/png;base64,{{ qr_code }}" alt="QR Code">
            <p>Or enter this secret manually: {{ secret }}</p>
            <a href="{{ url_for('login') }}">Login</a>
        ''', qr_code=img_base64, secret=users_db[username]['totp_secret'])
    
    return '''
        <form method="post">
            <input type="text" name="username" placeholder="Username" required>
            <input type="password" name="password" placeholder="Password" required>
            <button type="submit">Register</button>
        </form>
    '''

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        
        if not username or not password:
            return "Username and password required", 400
            
        user = users_db.get(username)
        if not user or not check_password_hash(user['password_hash'], password):
            return "Invalid credentials", 401
            
        # Generate temporary session token for MFA verification
        temp_token = generate_secure_token()
        session['temp_token'] = temp_token
        session['username'] = username
        
        # Store MFA token for verification
        mfa_token = generate_secure_token()
        store_mfa_token(username, mfa_token)
        
        return redirect(url_for('verify_mfa'))
    
    return '''
        <form method="post">
            <input type="text" name="username" placeholder="Username" required>
            <input type="password" name="password" placeholder="Password" required>
            <button type="submit">Login</button>
        </form>
    '''

@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if 'temp_token' not in session:
        return redirect(url_for('login'))
    
    username = session.get('username')
    if not username:
        return redirect(url_for('login'))
    
    if request.method == 'POST':
        otp = request.form.get('otp')
        if not otp:
            return "OTP required", 400
            
        user = users_db.get(username)
        if not user:
            return redirect(url_for('login'))
            
        # Verify OTP
        totp = pyotp.TOTP(user['totp_secret'])
        if not totp.verify(otp, valid_window=2):
            return "Invalid OTP", 401
            
        # Clear temp token and set session
        session.pop('temp_token', None)
        session['user_id'] = username
        session['authenticated'] = True
        
        # Remove MFA token after successful verification
        if username in mfa_tokens:
            del mfa_tokens[username]
            
        return redirect(url_for('dashboard'))
    
    return '''
        <form method="post">
            <input type="text" name="otp" placeholder="Enter 6-digit OTP" required>
            <button type="submit">Verify</button>
        </form>
    '''

@app.route('/dashboard')
def dashboard():
    if not session.get('authenticated'):
        return redirect(url_for('login'))
    
    return f"Welcome to your dashboard, {session.get('user_id')}!"

@app.route('/protected')
def protected():
    if not session.get('authenticated'):
        return redirect(url_for('login'))
    
    return "This is a protected resource."

